describe('Cycle 1 — no-empty-catch', () => {
  it('should block empty catch block', () => {
    const violations = runCycle1('try { x(); } catch (e) {}', '.js', 'file-write');
    assert.ok(violations.some(v => v.ruleId === 'no-empty-catch'));
  });
  it('should not trigger when catch has a body', () => {
    const violations = runCycle1('try { x(); } catch (e) { console.error(e); throw e; }', '.js', 'file-write');
    assert.ok(!violations.some(v => v.ruleId === 'no-empty-catch'));
  });
  it('should not trigger for Python files', () => {
    const violations = runCycle1('try { x(); } catch (e) {}', '.py', 'file-write');
    assert.ok(!violations.some(v => v.ruleId === 'no-empty-catch'));
  });
});

