// ─── Violation metadata ─────────────────────────────────────────────────────

describe('Violation metadata', () => {
  it('should include severity field', () => {
    const violations = runCycle2('data = pickle.loads(raw_bytes)', '.py', 'file-write');
    const v = violations.find(v => v.ruleId === 'no-pickle-load');
    assert.ok(v);
    assert.equal(v.severity, 'critical');
  });
  it('should include code field', () => {
    const violations = runCycle1('# TODO: fix this', '.py', 'file-write');
    const v = violations.find(v => v.ruleId === 'no-todo');
    assert.ok(v);
    assert.equal(v.code, 'quality.todo');
  });
  it('should include remediation field', () => {
    const violations = runCycle1('# TODO: fix this', '.py', 'file-write');
    const v = violations.find(v => v.ruleId === 'no-todo');
    assert.ok(v.remediation);
    assert.ok(v.remediation.length > 0);
  });
  it('should include priority field', () => {
    const violations = runCycle2('eval("code")', '.js', 'file-write');
    const v = violations.find(v => v.ruleId === 'no-eval');
    assert.ok(v);
    assert.equal(v.priority, 200);
  });
  it('should sort violations by priority descending', () => {
    const c1 = runCycle1('# TODO: fix', '.js', 'file-write');
    const c2 = runCycle2('eval("code")', '.js', 'file-write');
    const all = [...c1, ...c2].sort((a, b) => b.priority - a.priority);
    if (all.length >= 2) {
      assert.ok(all[0].priority >= all[1].priority);
    }
  });
});

