// ─── getAllRules ─────────────────────────────────────────────────────────────

describe('getAllRules()', () => {
  it('should return object with cycle1, cycle2, cycle4 keys', () => {
    const rules = getAllRules();
    assert.ok(rules.cycle1, 'Missing cycle1');
    assert.ok(rules.cycle2, 'Missing cycle2');
    assert.ok(rules.cycle4, 'Missing cycle4');
  });
  it('should have >15 total rules across all cycles', () => {
    const rules = getAllRules();
    const total = rules.cycle1.length + rules.cycle2.length + rules.cycle4.length;
    assert.ok(total > 15, 'Expected >15 rules, got ' + total);
  });
  it('every rule should have id, description, and message', () => {
    const rules = getAllRules();
    const allRules = [...rules.cycle1, ...rules.cycle2, ...rules.cycle4];
    for (const rule of allRules) {
      assert.ok(rule.id, 'Rule missing id');
      assert.ok(rule.description, 'Rule ' + rule.id + ' missing description');
      assert.ok(rule.message, 'Rule ' + rule.id + ' missing message');
    }
  });
  it('cycle1+cycle2 rules should have severity and code fields', () => {
    const rules = getAllRules();
    const allRules = [...rules.cycle1, ...rules.cycle2];
    const withSev = allRules.filter(r => r.severity);
    assert.ok(withSev.length >= 10, 'Expected >=10 rules with severity, got ' + withSev.length);
    for (const r of withSev) {
      assert.ok(r.code, 'Rule ' + r.id + ' has severity but no code');
    }
  });
});
